   1→import { createContext, useContext, useReducer, useCallback } from 'react';
   2→import { createSketchProject } from '../domain/sketchModels';
   3→import { sanitizePartDimensions, sanitizePartPosition } from '../domain/validation';
   4→import { resolveConstraints } from '../domain/constraintResolver';
   5→import { updateBoundDimensionEndpoints } from '../domain/dimensionBinding';
   6→import { generateId } from '@/domain/ids';
   7→import { generateObjectFromTemplate } from '../domain/objectGenerator';
   8→import { normalizeSketchObjects } from '../domain/objectModels';
   9→
  10→const SketchContext = createContext(null);
  11→const HISTORY_LIMIT = 80;
  12→
  13→function snapshotSketch(sketchProject) {
  14→  return JSON.stringify(sketchProject);
  15→}
  16→
  17→function applyUpdate(state, nextProject, recordHistory = true) {
  18→  const normalizedProject = normalizeSketchObjects(nextProject);
  19→  const nextSnapshot = snapshotSketch(normalizedProject);
  20→  const history = recordHistory
  21→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
  22→    : state.history;
  23→
  24→  return {
  25→    ...state,
  26→    history,
  27→    future: recordHistory ? [] : state.future,
  28→    project: normalizedProject,
  29→    isDirty: nextSnapshot !== state.savedSnapshot,
  30→  };
  31→}
  32→
  33→function mergePart(existing, updates) {
  34→  const merged = { ...existing, ...updates };
  35→  if (updates.position) {
  36→    merged.position = { ...existing.position, ...updates.position };
  37→  }
  38→  if (updates.rotation) {
  39→    merged.rotation = { ...existing.rotation, ...updates.rotation };
  40→  }
  41→  return merged;
  42→}
  43→
  44→function sanitizePart(part) {
  45→  if (part.type === 'dimension') return part;
  46→  return sanitizePartPosition(sanitizePartDimensions(part));
  47→}
  48→
  49→function applyConstraints(project) {
  50→  const constraints = project.constraints || [];
  51→  if (constraints.length === 0) return project;
  52→
  53→  const resolved = resolveConstraints(constraints, project.parts);
  54→  if (resolved.size === 0) return project;
  55→
  56→  return {
  57→    ...project,
  58→    parts: project.parts.map((part) => {
  59→      const newPos = resolved.get(part.id);
  60→      return newPos ? { ...part, position: newPos } : part;
  61→    }),
  62→  };
  63→}
  64→
  65→function updateBoundDimensions(project, updatedPartId) {
  66→  const updatedPart = project.parts.find((part) => part.id === updatedPartId);
  67→  if (!updatedPart) return project;
  68→
  69→  let changed = false;
  70→  const newParts = project.parts.map((part) => {
  71→    if (part.type === 'dimension' && part.boundPartId === updatedPartId) {
  72→      changed = true;
  73→      return updateBoundDimensionEndpoints(part, updatedPart);
  74→    }
  75→    return part;
  76→  });
  77→
  78→  return changed ? { ...project, parts: newParts } : project;
  79→}
  80→
  81→function clonePart(part, idMap) {
  82→  const newId = generateId('part');
  83→  idMap.set(part.id, newId);
  84→  return {
  85→    ...part,
  86→    id: newId,
  87→    name: `${part.name} (copy)`,
  88→    objectId: part.objectId || null,
  89→    source: 'manual',
  90→    locked: false,
  91→    position: {
  92→      ...part.position,
  93→      x: part.position.x + 50,
  94→      y: part.position.y + 50,
  95→    },
  96→  };
  97→}
  98→
  99→function getManagedObject(project, objectId) {
 100→  if (!objectId) return null;
 101→  return (project.objects || []).find((object) => object.id === objectId) || null;
 102→}
 103→
 104→function getManagedObjectForPart(project, partId) {
 105→  const part = project.parts.find((entry) => entry.id === partId);
 106→  const object = part?.objectId ? getManagedObject(project, part.objectId) : null;
 107→  return object?.editingPolicy === 'parametric' ? object : null;
 108→}
 109→
 110→function getManagedObjectForAssembly(project, assemblyId) {
 111→  const assembly = project.assemblies.find((entry) => entry.id === assemblyId);
 112→  const object = assembly?.objectId ? getManagedObject(project, assembly.objectId) : null;
 113→  return object?.editingPolicy === 'parametric' ? object : null;
 114→}
 115→
 116→function filterConstraintsForRemovedParts(constraints, idsToRemove) {
 117→  return constraints
 118→    .map((constraint) => {
 119→      // For equal_spacing, remove deleted parts from the partIds list
 120→      if (constraint.type === 'equal_spacing') {
 121→        const filtered = (constraint.partIds || []).filter((id) => !idsToRemove.has(id));
 122→        // Also clear referencePartId if it was removed
 123→        const refCleared = idsToRemove.has(constraint.referencePartId)
 124→          ? null
 125→          : constraint.referencePartId;
 126→        if (filtered.length < 2) return null; // not enough parts left
 127→        return { ...constraint, partIds: filtered, referencePartId: refCleared };
 128→      }
 129→      // Standard constraints: remove if either source or target is deleted
 130→      if (idsToRemove.has(constraint.sourcePartId) || idsToRemove.has(constraint.targetPartId)) {
 131→        return null;
 132→      }
 133→      return constraint;
 134→    })
 135→    .filter(Boolean);
 136→}
 137→
 138→function removePartsAndAssemblies(project, { partIds, assemblyIds }) {
 139→  const idsToRemove = new Set(partIds);
 140→  const assemblyIdSet = new Set(assemblyIds);
 141→
 142→  const childIds = new Set(
 143→    project.parts.filter((part) => idsToRemove.has(part.parentId)).map((part) => part.id)
 144→  );
 145→  for (const childId of childIds) idsToRemove.add(childId);
 146→
 147→  const constraints = filterConstraintsForRemovedParts(
 148→    project.constraints || [],
 149→    idsToRemove
 150→  );
 151→
 152→  return {
 153→    ...project,
 154→    parts: project.parts
 155→      .filter((part) => !idsToRemove.has(part.id))
 156→      .map((part) => {
 157→        if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 158→          return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 159→        }
 160→        return part;
 161→      }),
 162→    assemblies: project.assemblies.filter((assembly) => !assemblyIdSet.has(assembly.id)),
 163→    constraints,
 164→  };
 165→}
 166→
 167→function removeObjectArtifacts(project, objectId) {
 168→  const partIds = project.parts
 169→    .filter((part) => part.objectId === objectId)
 170→    .map((part) => part.id);
 171→  const assemblyIds = project.assemblies
 172→    .filter((assembly) => assembly.objectId === objectId)
 173→    .map((assembly) => assembly.id);
 174→
 175→  return removePartsAndAssemblies(project, { partIds, assemblyIds });
 176→}
 177→
 178→function retargetManagedViewports(sheets, objectId, oldAssemblyIds = []) {
 179→  const oldAssemblyIdSet = new Set(oldAssemblyIds);
 180→
 181→  return (sheets || []).map((sheet) => ({
 182→    ...sheet,
 183→    viewports: (sheet.viewports || []).map((viewport) => {
 184→      if (viewport.sourceRefId !== objectId && !oldAssemblyIdSet.has(viewport.sourceRefId)) {
 185→        return viewport;
 186→      }
 187→
 188→      if (viewport.sourceView === 'sketch_assembly_top') {
 189→        return { ...viewport, sourceView: 'sketch_object_top', sourceRefId: objectId };
 190→      }
 191→      if (viewport.sourceView === 'sketch_assembly_front') {
 192→        return { ...viewport, sourceView: 'sketch_object_front', sourceRefId: objectId };
 193→      }
 194→      if (viewport.sourceView === 'sketch_assembly_side') {
 195→        return { ...viewport, sourceView: 'sketch_object_side', sourceRefId: objectId };
 196→      }
 197→      if (viewport.sourceView === 'sketch_part_list') {
 198→        return { ...viewport, sourceRefId: objectId, sourceObjectId: objectId };
 199→      }
 200→
 201→      return viewport;
 202→    }),
 203→  }));
 204→}
 205→
 206→function detachManagedObject(project, objectId) {
 207→  return {
 208→    ...project,
 209→    objects: (project.objects || []).map((object) => (
 210→      object.id === objectId
 211→        ? {
 212→            ...object,
 213→            source: 'custom',
 214→            editingPolicy: 'manual',
 215→            templateType: null,
 216→            templateParams: null,
 217→            summary: object.summary || 'Detached custom object',
 218→            updatedAt: new Date().toISOString(),
 219→          }
 220→        : object
 221→    )),
 222→    assemblies: project.assemblies.map((assembly) => (
 223→      assembly.objectId === objectId
 224→        ? {
 225→            ...assembly,
 226→            source: 'manual',
 227→            role: assembly.role || null,
 228→          }
 229→        : assembly
 230→    )),
 231→    parts: project.parts.map((part) => (
 232→      part.objectId === objectId
 233→        ? {
 234→          ...part,
 235→            source: 'manual',
 236→            locked: false,
 237→          }
 238→        : part
 239→    )),
 240→  };
 241→}
 242→
 243→function addGeneratedObject(project, generated) {
 244→  return {
 245→    ...project,
 246→    objects: [...(project.objects || []), generated.object],
 247→    assemblies: [...project.assemblies, ...generated.assemblies],
 248→    parts: [...project.parts, ...generated.parts.map(sanitizePart)],
 249→  };
 250→}
 251→
 252→function collectConstraintsForObject(project, objectId) {
 253→  const objectPartIds = new Set(
 254→    project.parts.filter((part) => part.objectId === objectId).map((part) => part.id)
 255→  );
 256→  return (project.constraints || []).filter((constraint) => {
 257→    if (constraint.type === 'equal_spacing') {
 258→      return (constraint.partIds || []).some((id) => objectPartIds.has(id));
 259→    }
 260→    return objectPartIds.has(constraint.sourcePartId) || objectPartIds.has(constraint.targetPartId);
 261→  });
 262→}
 263→
 264→function buildRoleMap(parts, objectId) {
 265→  const map = new Map();
 266→  for (const part of parts) {
 267→    if (part.objectId === objectId && part.generatedRole) {
 268→      map.set(part.id, part.generatedRole);
 269→    }
 270→  }
 271→  return map;
 272→}
 273→
 274→function buildReverseRoleMap(parts, objectId) {
 275→  const map = new Map();
 276→  for (const part of parts) {
 277→    if (part.objectId === objectId && part.generatedRole) {
 278→      map.set(part.generatedRole, part.id);
 279→    }
 280→  }
 281→  return map;
 282→}
 283→
 284→function remapConstraints(constraints, oldRoleMap, newRoleMap) {
 285→  return constraints
 286→    .map((constraint) => {
 287→      if (constraint.type === 'equal_spacing') {
 288→        const newPartIds = (constraint.partIds || []).map((id) => {
 289→          const role = oldRoleMap.get(id);
 290→          return role ? (newRoleMap.get(role) || null) : id;
 291→        }).filter(Boolean);
 292→
 293→        let newRefId = constraint.referencePartId;
 294→        if (newRefId) {
 295→          const refRole = oldRoleMap.get(newRefId);
 296→          newRefId = refRole ? (newRoleMap.get(refRole) || null) : newRefId;
 297→        }
 298→
 299→        if (newPartIds.length < 2) return null;
 300→        return { ...constraint, partIds: newPartIds, referencePartId: newRefId };
 301→      }
 302→
 303→      let newSourceId = constraint.sourcePartId;
 304→      let newTargetId = constraint.targetPartId;
 305→
 306→      const sourceRole = oldRoleMap.get(newSourceId);
 307→      if (sourceRole) newSourceId = newRoleMap.get(sourceRole) || null;
 308→
 309→      const targetRole = oldRoleMap.get(newTargetId);
 310→      if (targetRole) newTargetId = newRoleMap.get(targetRole) || null;
 311→
 312→      if (!newSourceId || !newTargetId) return null;
 313→      return { ...constraint, sourcePartId: newSourceId, targetPartId: newTargetId };
 314→    })
 315→    .filter(Boolean);
 316→}
