 914→      const previous = state.history[state.history.length - 1];
 915→      return {
 916→        ...state,
 917→        project: previous,
 918→        history: state.history.slice(0, -1),
 919→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
 920→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
 921→      };
 922→    }
 923→
 924→    case 'REDO': {
 925→      if (state.future.length === 0) return state;
 926→      const next = state.future[0];
 927→      return {
 928→        ...state,
 929→        project: next,
 930→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
 931→        future: state.future.slice(1),
 932→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
 933→      };
 934→    }
 935→
 936→    case 'MARK_SAVED':
 937→      return {
 938→        ...state,
 939→        isDirty: false,
 940→        savedSnapshot: snapshotSketch(state.project),
 941→      };
 942→
 943→    default:
 944→      return state;
 945→  }
 946→}
