 972→export function useSketch() {
 973→  const ctx = useContext(SketchContext);
 974→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
 975→  const { state, dispatch } = ctx;
 976→
 977→  const getPart = useCallback(
 978→    (partId) => state.project.parts.find((part) => part.id === partId) || null,
 979→    [state.project.parts]
 980→  );
 981→
 982→  const getAssembly = useCallback(
 983→    (assemblyId) => state.project.assemblies.find((assembly) => assembly.id === assemblyId) || null,
 984→    [state.project.assemblies]
 985→  );
 986→
 987→  const getObject = useCallback(
 988→    (objectId) => (state.project.objects || []).find((object) => object.id === objectId) || null,
 989→    [state.project.objects]
 990→  );
 991→
 992→  const getPartsForAssembly = useCallback(
 993→    (assemblyId) => state.project.parts.filter((part) => part.assemblyId === assemblyId),
 994→    [state.project.parts]
 995→  );
 996→
 997→  const getChildParts = useCallback(
 998→    (parentId) => state.project.parts.filter((part) => part.parentId === parentId),
 999→    [state.project.parts]
1000→  );
1001→
1002→  const getAssembliesForObject = useCallback(
1003→    (objectId) => state.project.assemblies.filter((assembly) => assembly.objectId === objectId),
1004→    [state.project.assemblies]
1005→  );
1006→
1007→  return {
1008→    project: state.project,
1009→    isDirty: state.isDirty,
1010→    canUndo: state.history.length > 0,
1011→    canRedo: state.future.length > 0,
1012→    dispatch,
1013→    getPart,
1014→    getAssembly,
1015→    getObject,
1016→    getPartsForAssembly,
1017→    getChildParts,
1018→    getAssembliesForObject,
1019→  };
1020→}
