 19→function screenToModel(screenX, screenY, viewport, svgRect) {
 20→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 21→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 22→  return { x, y };
 23→}
 24→
 25→function useSketchTool() {
 26→  const { dispatch: sketchDispatch, project } = useSketch();
 27→  const {
 28→    activeTool, viewport, snapEnabled, selectedId, selectedType,
 29→    toolState, activeView, activeAssemblyId, dispatch: editorDispatch,
 30→  } = useSketchEditor();
 31→
 32→  const ctx = {
 33→    dispatch: sketchDispatch,
 34→    editorDispatch,
 35→    project,
 36→    activeView,
 37→    activeAssemblyId,
 38→    viewport,
 39→    snapEnabled,
 40→    selectedId,
 41→    selectedType,
 42→  };
 43→
 44→  switch (activeTool) {
 45→    case 'panel':
 46→    case 'leg':
 47→    case 'frame':
 48→    case 'cutout':
 49→    case 'hole':
 50→      return createPartPlaceHandler({ ...ctx, partType: activeTool });
 51→    case 'dimension':
 52→      return createDimensionHandler(ctx);
 53→    case 'select':
 54→    default:
 55→      return createSketchSelectHandler(ctx);
 56→  }
 57→}
