 31→function PartDetailContent({ source }) {
 32→  const { part, viewLayouts } = source;
 33→  const viewLabels = { top: 'TOP', front: 'FRONT', side: 'SIDE' };
 34→
 35→  return (
 36→    <g>
 37→      {viewLayouts.map((layout) => {
 38→        const isHoleInTop = part.type === 'hole' && layout.view === 'top';
 39→        const isSubtractive = part.type === 'cutout' || part.type === 'hole';
 40→        const strokeDash = isSubtractive ? '6 4' : undefined;
 41→
 42→        return (
 43→          <g key={layout.view} transform={`translate(${layout.offsetX - layout.svgX}, ${layout.offsetY - layout.svgY})`}>
 44→            {isHoleInTop ? (
 45→              <ellipse
 46→                cx={layout.svgX + layout.width / 2}
 47→                cy={layout.svgY + layout.height / 2}
 48→                rx={layout.width / 2}
 49→                ry={layout.height / 2}
 50→                fill="none"
 51→                stroke={SHEET_COLORS.text}
 52→                strokeWidth={2}
 53→                strokeDasharray={strokeDash}
 54→              />
 55→            ) : (
 56→              <rect
 57→                x={layout.svgX}
 58→                y={layout.svgY}
 59→                width={layout.width}
 60→                height={layout.height}
 61→                fill="none"
 62→                stroke={SHEET_COLORS.text}
 63→                strokeWidth={2}
 64→                strokeDasharray={strokeDash}
 65→              />
 66→            )}
 67→            {/* View label */}
 68→            <text
 69→              x={layout.svgX + layout.width / 2}
 70→              y={layout.svgY + layout.height + 200}
 71→              textAnchor="middle"
 72→              fontSize={120}
 73→              fill={SHEET_COLORS.textMuted}
 74→              fontWeight={600}
 75→            >
 76→              {viewLabels[layout.view]}
 77→            </text>
 78→            {/* Auto-dimension: width */}
 79→            {layout.width > 0 && (() => {
 80→              const fig = createDimensionFigure({
 81→                id: `auto-w-${layout.view}`,
 82→                startPoint: { x: layout.svgX, y: layout.svgY },
 83→                endPoint: { x: layout.svgX + layout.width, y: layout.svgY },
 84→                mode: 'aligned',
 85→                offset: -200,
 86→                source: 'auto',
 87→              });
 88→              if (!fig) return null;
 89→              return (
 90→                <g>
 91→                  {fig.extensionLines.map((line, i) => (
 92→                    <line
 93→                      key={`ext-w-${i}`}
 94→                      x1={line.start.x} y1={line.start.y}
 95→                      x2={line.end.x} y2={line.end.y}
 96→                      stroke={SHEET_COLORS.textMuted}
 97→                      strokeWidth={1}
 98→                    />
 99→                  ))}
100→                  <line
101→                    x1={fig.lineStart.x} y1={fig.lineStart.y}
102→                    x2={fig.lineEnd.x} y2={fig.lineEnd.y}
103→                    stroke={SHEET_COLORS.text}
104→                    strokeWidth={1}
105→                  />
106→                  {fig.arrowheads.map((arrow, i) => (
107→                    <polygon
108→                      key={`arr-w-${i}`}
109→                      points={`${arrow.tip.x},${arrow.tip.y} ${arrow.left.x},${arrow.left.y} ${arrow.right.x},${arrow.right.y}`}
110→                      fill={SHEET_COLORS.text}
111→                    />
112→                  ))}
113→                  <text
114→                    x={fig.text.position.x}
115→                    y={fig.text.position.y}
116→                    textAnchor="middle"
117→                    dominantBaseline="central"
118→                    transform={`rotate(${fig.text.angle} ${fig.text.position.x} ${fig.text.position.y})`}
119→                    fontSize={100}
120→                    fill={SHEET_COLORS.text}
121→                  >
122→                    {fig.text.value}
123→                  </text>
124→                </g>
125→              );
126→            })()}
127→            {/* Auto-dimension: height */}
128→            {layout.height > 0 && (() => {
129→              const fig = createDimensionFigure({
130→                id: `auto-h-${layout.view}`,
131→                startPoint: { x: layout.svgX, y: layout.svgY },
132→                endPoint: { x: layout.svgX, y: layout.svgY + layout.height },
133→                mode: 'aligned',
134→                offset: -200,
135→                source: 'auto',
136→              });
137→              if (!fig) return null;
138→              return (
139→                <g>
140→                  {fig.extensionLines.map((line, i) => (
141→                    <line
142→                      key={`ext-h-${i}`}
143→                      x1={line.start.x} y1={line.start.y}
144→                      x2={line.end.x} y2={line.end.y}
145→                      stroke={SHEET_COLORS.textMuted}
146→                      strokeWidth={1}
147→                    />
148→                  ))}
149→                  <line
150→                    x1={fig.lineStart.x} y1={fig.lineStart.y}
151→                    x2={fig.lineEnd.x} y2={fig.lineEnd.y}
152→                    stroke={SHEET_COLORS.text}
153→                    strokeWidth={1}
154→                  />
155→                  {fig.arrowheads.map((arrow, i) => (
156→                    <polygon
157→                      key={`arr-h-${i}`}
158→                      points={`${arrow.tip.x},${arrow.tip.y} ${arrow.left.x},${arrow.left.y} ${arrow.right.x},${arrow.right.y}`}
159→                      fill={SHEET_COLORS.text}
160→                    />
161→                  ))}
162→                  <text
163→                    x={fig.text.position.x}
164→                    y={fig.text.position.y}
165→                    textAnchor="middle"
166→                    dominantBaseline="central"
167→                    transform={`rotate(${fig.text.angle} ${fig.text.position.x} ${fig.text.position.y})`}
168→                    fontSize={100}
169→                    fill={SHEET_COLORS.text}
170→                  >
171→                    {fig.text.value}
172→                  </text>
173→                </g>
174→              );
175→            })()}
176→          </g>
177→        );
178→      })}
179→    </g>
180→  );
181→}
