183→function PartListContent({ source }) {
184→  const { rows, columnWidths, headers, rowHeight, headerHeight, bounds } = source;
185→  const tableWidth = bounds.maxX - bounds.minX;
186→
187→  let colX = 0;
188→  const colPositions = columnWidths.map((w) => {
189→    const x = colX;
190→    colX += w;
191→    return x;
192→  });
193→
194→  return (
195→    <g>
196→      {/* Table border */}
197→      <rect
198→        x={0} y={0}
199→        width={tableWidth}
200→        height={headerHeight + rows.length * rowHeight}
201→        fill="none"
202→        stroke={SHEET_COLORS.border}
203→        strokeWidth={0.5}
204→      />
205→      {/* Header row */}
206→      <rect
207→        x={0} y={0}
208→        width={tableWidth} height={headerHeight}
209→        fill={SHEET_COLORS.panelFill}
210→        stroke={SHEET_COLORS.border}
211→        strokeWidth={0.3}
212→      />
213→      {headers.map((header, i) => (
214→        <text
215→          key={`hdr-${i}`}
216→          x={colPositions[i] + columnWidths[i] / 2}
217→          y={headerHeight / 2}
218→          textAnchor="middle"
219→          dominantBaseline="central"
220→          fontSize={8}
221→          fontWeight={600}
222→          fill={SHEET_COLORS.text}
223→          letterSpacing={0.3}
224→        >
225→          {header}
226→        </text>
227→      ))}
228→      {/* Column dividers */}
229→      {colPositions.slice(1).map((x, i) => (
230→        <line
231→          key={`col-${i}`}
232→          x1={x} y1={0}
233→          x2={x} y2={headerHeight + rows.length * rowHeight}
234→          stroke={SHEET_COLORS.divider}
235→          strokeWidth={0.2}
236→        />
237→      ))}
238→      {/* Data rows */}
239→      {rows.map((row, rowIndex) => {
240→        const y = headerHeight + rowIndex * rowHeight;
241→        const values = [
242→          String(row.item),
243→          row.name,
244→          row.type,
245→          row.material,
246→          String(row.qty),
247→          row.dims,
248→        ];
249→        return (
250→          <g key={`row-${rowIndex}`}>
251→            <line
252→              x1={0} y1={y}
253→              x2={tableWidth} y2={y}
254→              stroke={SHEET_COLORS.divider}
255→              strokeWidth={0.15}
256→            />
257→            {values.map((val, colIndex) => (
258→              <text
259→                key={`cell-${rowIndex}-${colIndex}`}
260→                x={colPositions[colIndex] + columnWidths[colIndex] / 2}
261→                y={y + rowHeight / 2}
262→                textAnchor="middle"
263→                dominantBaseline="central"
264→                fontSize={7}
265→                fill={SHEET_COLORS.text}
266→              >
267→                {val}
268→              </text>
269→            ))}
270→          </g>
271→        );
272→      })}
273→    </g>
274→  );
275→}
