277→export default function SketchSheetViewportContent({ source }) {
278→  if (!source || source.kind === 'empty') return null;
279→
280→  if (source.kind === 'sketch_object' || source.kind === 'sketch_assembly') {
281→    return <AssemblyViewContent source={source} />;
282→  }
283→
284→  if (source.kind === 'sketch_part_detail') {
285→    return <PartDetailContent source={source} />;
286→  }
287→
288→  if (source.kind === 'sketch_part_list') {
289→    return <PartListContent source={source} />;
290→  }
291→
292→  return null;
293→}
